// Load script setelah DOM berhasil dimuat
$(function () {
    
    // Fungsi load statisik billboard
    function loadStats() {}

    // Inisialisasi data tabel billboard-list
    TableHelper.init("#tableBillboardList", {
        filters: [4, 5], // filter untuk Status & Jenis saja
        columns: [
            {
                data: "id",
                title: "ID",
                className: "dt-head-center dt-body-center",
                searchable: false,
            },
            {
                data: "judul",
                title: "Judul",
                className: "dt-head-center",
            },
            {
                data: "area",
                title: "Area",
                className: "dt-head-center",
            },
            {
                data: "lokasi",
                title: "Lokasi",
                className: "dt-head-center",
            },
            {
                data: "status",
                title: "Status",
                className: "dt-head-center dt-body-center",
                orderable: false,
                searchable: false,
                render: function (data, type) {
                    return data == 1
                        ? `<span class="lencana bg-success" data-value="${data}">Tersedia</span>`
                        : `<span class="lencana bg-secondary" data-value="${data}">Tersewa</span>`;
                },
            },
            {
                data: "jenis",
                title: "Jenis",
                className: "dt-head-center dt-body-center",
                orderable: false,
                searchable: false,
            },
            {
                data: "ukuran",
                title: "Ukuran (m)",
                className: "dt-head-center dt-body-center",
                orderable: false,
            },
            {
                data: "unit",
                title: "Unit",
                className: "dt-head-center dt-body-center",
                orderable: false,
                searchable: false,
            },
            {
                data: "koordinat",
                title: "Koordinat",
                className: "dt-head-center dt-body-center",
                orderable: false,
                searchable: false,
            },
            {
                data: "gambar",
                title: "Gambar",
                className: "dt-head-center dt-body-center dt-gambar",
                orderable: false,
                searchable: false,
                render: {
                    _: (gambar) => gambar,
                    display: (gambar) =>
                        gambar
                            ? `<img src="/storage/upload/billboard/thum_${gambar}" 
                                        alt="Gambar Billboard" 
                                        class="img-thumbnail rounded shadow-sm billboard-thumb" 
                                        style="width: 100px; height: auto; object-fit: cover;" 
                                        data-full="/storage/upload/billboard/${gambar}"/>`
                            : `<span class="text-muted"></span>`,
                },
            },
        ],
        columnDefs: [
            { responsivePriority: 1, targets: [1, 4] }, // kolom penting utama
            { responsivePriority: 2, targets: [2, 3, 5] }, // kolom kedua
            { responsivePriority: 3, targets: [0, 6, 7, 8, 9] }, // kolom ketiga
        ],
    });

    // Event klik thumbnail
    $(document).on("click", ".billboard-thumb", function () {
        const fullImageUrl = $(this).data("full");
        $("#previewBillboardImage").attr("src", fullImageUrl);
        $("#modalGambarBillboard").modal("show");
    });

});
